<?php $users=$access['users']??[];$clientContext=!is_master()&&(user()['active_company_type']??'')==='cliente'; ?>
<section class="page-heading split"><div><span class="eyebrow blue">Identidades e organizações</span><h1>Usuários</h1><p>Uma pessoa pode participar de várias empresas e possuir um perfil diferente em cada uma.</p></div><?php if(can('users','create')): ?><button class="btn primary" data-user-create><i class="bi bi-person-plus"></i> Novo usuário</button><?php endif; ?></section>
<?php if($flash): ?><div class="alert <?= $flash['type']==='success'?'success':'error' ?>"><i class="bi <?= $flash['type']==='success'?'bi-check-circle':'bi-exclamation-circle' ?>"></i> <?= e($flash['message']) ?></div><?php endif; ?>
<section class="panel"><div class="panel-head"><div><h2>Pessoas com acesso</h2><p>Os vínculos determinam quais empresas e clientes cada pessoa poderá acessar.</p></div></div><div class="table-wrap"><table><thead><tr><th>Usuário</th><th>Empresas e perfis</th><th>Último acesso</th><th>Situação</th><th>Ações</th></tr></thead><tbody>
<?php if(!$users): ?><tr><td colspan="5"><div class="table-empty"><i class="bi bi-people"></i><strong>Nenhum usuário encontrado</strong><span>Cadastre ou vincule uma pessoa às empresas disponíveis.</span></div></td></tr><?php endif; ?>
<?php foreach($users as $account): $links=[];foreach(array_filter(explode(',',(string)$account['vinculo_ids'])) as $pair){[$companyId,$profileId]=array_pad(explode(':',$pair),2,0);$links[(string)$companyId]=(string)$profileId;}$payload=['id'=>(int)$account['id'],'nome'=>$account['nome'],'email'=>$account['email'],'foto_url'=>$account['foto']?url($account['foto']):null,'ativo'=>(int)$account['ativo'],'proprio'=>(int)$account['id']===(int)(user()['id']??0),'vinculos'=>$links]; ?>
<tr><td><div class="entity-cell"><span class="avatar access-avatar"><?php if($account['foto']): ?><img src="<?= url($account['foto']) ?>" alt="Foto de <?= e($account['nome']) ?>"><?php else: ?><?= e(strtoupper(substr($account['nome'],0,2))) ?><?php endif; ?></span><div><strong><?= e($account['nome']) ?></strong><small><?= e($account['email']) ?></small></div></div></td><td><div class="membership-summary"><?php foreach(array_filter(explode(';;',(string)$account['vinculos'])) as $link): [$companyName,$profileName]=array_pad(explode('|',$link,2),2,''); ?><span><strong><?= e($companyName) ?></strong><small><?= e($profileName) ?></small></span><?php endforeach; ?></div></td><td><?= $account['ultimo_acesso']?e(date('d/m/Y H:i',strtotime($account['ultimo_acesso']))):'Nunca acessou' ?></td><td><span class="status <?= $account['ativo']?'active':'inactive' ?>"><?= $account['ativo']?'Ativo':'Inativo' ?></span></td><td><div class="row-actions"><?php if(can('users','update')): ?><button class="action-btn" data-user-edit data-user="<?= e(json_encode($payload,JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES)) ?>" aria-label="Editar <?= e($account['nome']) ?>"><i class="bi bi-pencil"></i></button><?php endif; ?><?php if(can('users','delete')&&(int)$account['id']!==(int)(user()['id']??0)&&$account['ativo']): ?><button class="action-btn danger" data-user-delete data-id="<?= (int)$account['id'] ?>" data-name="<?= e($account['nome']) ?>" aria-label="Desativar <?= e($account['nome']) ?>"><i class="bi bi-person-x"></i></button><?php endif; ?></div></td></tr>
<?php endforeach; ?></tbody></table></div></section>

<div class="modal" id="user-modal" aria-hidden="true"><div class="modal-dialog access-dialog"><button class="modal-close" data-modal-close aria-label="Fechar"><i class="bi bi-x-lg"></i></button><div class="modal-content"><span class="eyebrow blue">Pessoa e vínculos</span><h2 data-user-modal-title>Novo usuário</h2><p>O mesmo e-mail pode receber novos vínculos sem criar uma conta duplicada.</p><form method="post" enctype="multipart/form-data" data-user-form data-client-context="<?= $clientContext?'1':'0' ?>"><?= csrf_field() ?><input type="hidden" name="action" value="create"><input type="hidden" name="id"><div class="form-grid"><label class="full image-upload user-image-upload"><span class="image-preview user-photo-preview" data-user-photo-preview><i class="bi bi-person"></i></span><span><strong>Foto da pessoa (opcional)</strong><small>JPG, PNG ou WEBP, com até 3 MB.</small><input type="file" name="foto" accept="image/jpeg,image/png,image/webp" data-user-photo></span></label><label>Nome completo<input name="nome" maxlength="140" required></label><label>E-mail de acesso<input type="email" name="email" maxlength="180" required></label><label class="full">Senha inicial ou nova senha<input type="password" name="senha" minlength="8" autocomplete="new-password" placeholder="Mínimo de 8 caracteres"><small>Obrigatória no primeiro cadastro. Na edição, deixe vazia para manter a senha.</small></label><?php if(!$clientContext): ?><label class="full user-type-filter">Tipo de organização<select data-user-type-filter><option value="volkswagen">Volkswagen — VWCO, fábrica ou concessionária</option><option value="cliente">Cliente — transportadora ou proprietário de frota</option><option value="todos">Todos os tipos — vínculo misto</option></select><small>Esta escolha filtra as empresas disponíveis para facilitar o cadastro.</small></label><?php endif; ?>
<fieldset class="full link-fieldset"><legend>Empresa e perfil de acesso</legend><p><?= $clientContext?'O vínculo com a empresa é obrigatório. Escolha o perfil somente para os usuários que você administra.':'Marque uma ou mais empresas e escolha o perfil que a pessoa terá em cada uma.' ?></p><div class="self-access-note" data-user-self-note hidden><i class="bi bi-shield-lock"></i><span>Seu vínculo, perfil e situação estão protegidos. Você pode atualizar somente seus dados pessoais e sua senha.</span></div><?php if(!$clientContext): ?><div class="selection-search search"><span><i class="bi bi-search"></i></span><input type="search" placeholder="Buscar empresa..." data-user-company-search></div><?php endif; ?><div class="membership-editor" data-user-company-list><?php foreach($access['companyOptions']??[] as $company): ?><label class="membership-option <?= $clientContext?'company-locked':'' ?>" data-user-company data-company-type="<?= e($company['tipo']) ?>" data-search-text="<?= e($company['nome_fantasia']) ?>"><span class="membership-check"><input type="checkbox" name="empresa_ids[]" value="<?= (int)$company['id'] ?>" data-user-company-check <?= $clientContext?'checked data-company-locked="1" aria-disabled="true"':'' ?>><i class="bi bi-building"></i><strong><?= e($company['nome_fantasia']) ?></strong><small><?= e($company['tipo']==='cliente'?'Cliente':($company['tipo']==='vwco'?'VWCO':'Concessionária')) ?></small></span><select name="perfil_empresa[<?= (int)$company['id'] ?>]" data-user-company-profile <?= $clientContext?'':'disabled' ?>><option value="">Selecione o perfil</option><?php foreach($access['profileOptions']??[] as $profile): ?><option value="<?= (int)$profile['id'] ?>" data-profile-type="<?= e($profile['tipo_empresa']) ?>"><?= e($profile['nome']) ?> · nível <?= (int)$profile['nivel'] ?></option><?php endforeach; ?></select></label><?php endforeach; ?></div></fieldset>
<label class="full check"><input type="checkbox" name="ativo" checked> Usuário ativo</label></div><div class="modal-actions"><button type="button" class="btn secondary" data-modal-close>Cancelar</button><button class="btn primary"><i class="bi bi-check-lg"></i> Salvar usuário</button></div></form></div></div></div>
<div class="modal" id="delete-user-modal" aria-hidden="true"><div class="modal-dialog confirm-dialog"><button class="modal-close" data-modal-close aria-label="Fechar"><i class="bi bi-x-lg"></i></button><div class="modal-content"><span class="confirm-icon"><i class="bi bi-person-x"></i></span><h2>Desativar usuário?</h2><p><strong data-delete-user-name></strong> não conseguirá entrar, mas seu histórico será preservado.</p><form method="post"><?= csrf_field() ?><input type="hidden" name="action" value="delete"><input type="hidden" name="id" data-delete-user-id><div class="modal-actions"><button type="button" class="btn secondary" data-modal-close>Cancelar</button><button class="btn danger">Desativar</button></div></form></div></div></div>
